  1	import React, { FC, useMemo } from 'react';
  2	import { Link } from 'react-router-dom-v5-compat';
  3	import classNames from 'classnames';
  4	
  5	import AlertsDrawer from '@kubevirt-utils/components/AlertsCard/AlertsDrawer';
  6	import {
  7	  ALERTS_SCOPE_KEY,
  8	  ALL_ALERTS,
  9	  VIEW_ALL_ALERTS_PATH,
 10	  VIRTUALIZATION_ONLY_ALERTS,
 11	} from '@kubevirt-utils/components/AlertsCard/utils/constants';
 12	import { SimplifiedAlerts } from '@kubevirt-utils/components/AlertsCard/utils/types';
 13	import {
 14	  alertScopeOptions,
 15	  removeVMAlerts,
 16	} from '@kubevirt-utils/components/AlertsCard/utils/utils';
 17	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
 18	import { useIsAdmin } from '@kubevirt-utils/hooks/useIsAdmin';
 19	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 20	import useLocalStorage from '@kubevirt-utils/hooks/useLocalStorage';
 21	import { Card, CardHeader, CardTitle, Popover, PopoverPosition } from '@patternfly/react-core';
 22	import { SelectOption } from '@patternfly/react-core';
 23	
 24	import './AlertsCard.scss';
 25	
 26	type AlertsCardProps = {
 27	  className?: string;
 28	  isOverviewPage?: boolean;
 29	  sortedAlerts: SimplifiedAlerts;
 30	};
 31	
 32	const AlertsCard: FC<AlertsCardProps> = ({ className, isOverviewPage = false, sortedAlerts }) => {
 33	  const { t } = useKubevirtTranslation();
 34	  const isAdmin = useIsAdmin();
 35	  const [alertScope, setAlertScope] = useLocalStorage(
 36	    ALERTS_SCOPE_KEY,
 37	    isAdmin ? VIRTUALIZATION_ONLY_ALERTS : ALL_ALERTS, // for admins show the number of virtualization health alerts by default
 38	  );
 39	
 40	  const alerts = useMemo(() => {
 41	    return !isOverviewPage || !isAdmin || alertScope === ALL_ALERTS
 42	      ? sortedAlerts
 43	      : removeVMAlerts(sortedAlerts);
 44	  }, [alertScope, isAdmin, isOverviewPage, sortedAlerts]);
 45	
 46	  // number of alerts according to the selected scope: Virtualization health only or all alerts
 47	  const alertsQuantity =
 48	    Object.values(alerts)?.reduce((acc, category) => acc + category?.length, 0) || 0;
 49	
 50	  return (
 51	    <Card className={classNames('alerts-card', className)}>
 52	      <CardHeader
 53	        {...(isOverviewPage && {
 54	          actions: {
 55	            actions: (
 56	              <>
 57	                {isAdmin && (
 58	                  <Link className="alerts-card__view-all-link" to={VIEW_ALL_ALERTS_PATH}>
 59	                    {t('View all')}
 60	                  </Link>
 61	                )}
 62	                {isAdmin ? (
 63	                  <FormPFSelect
 64	                    onSelect={(e, value) => setAlertScope(value)}
 65	                    popperProps={{ position: 'right' }}
 66	                    selected={alertScope}
 67	                    toggleProps={{ id: 'overview-alerts-card' }}
 68	                  >
 69	                    {alertScopeOptions().map((scope) => (
 70	                      <SelectOption
 71	                        description={scope.description}
 72	                        key={scope.key}
 73	                        value={scope.value}
 74	                      >
 75	                        {scope.value}
 76	                      </SelectOption>
 77	                    ))}
 78	                  </FormPFSelect>
 79	                ) : (
 80	                  <Popover
 81	                    bodyContent={
 82	                      <div>{t('Only VM-related alerts in your project will be shown')}</div>
 83	                    }
 84	                    aria-label="Only VM-related alerts notification"
 85	                    className="alerts-card__nonadmin-popover"
 86	                    enableFlip={false}
 87	                    hasAutoWidth
 88	                    maxWidth="250px"
 89	                    position={PopoverPosition.top}
 90	                  >
 91	                    <FormPFSelect
 92	                      onSelect={(e, value) => setAlertScope(value)}
 93	                      selected={alertScope}
 94	                      toggleProps={{ id: 'overview-alerts-card' }}
 95	                    >
 96	                      {alertScopeOptions().map((scope) => (
 97	                        <SelectOption
 98	                          description={scope.description}
 99	                          key={scope.key}
100	                          value={scope.value}
101	                        >
102	                          {scope.value}
103	                        </SelectOption>
104	                      ))}
105	                    </FormPFSelect>
106	                  </Popover>
107	                )}
108	              </>
109	            ),
110	            className: 'co-overview-card__actions alerts-card__actions',
111	            hasNoOffset: false,
112	          },
113	        })}
114	        className="alerts-card__header"
115	      >
116	        <CardTitle className="text-muted card-title">
117	          {t('Alerts ({{alertsQuantity}})', { alertsQuantity })}
118	        </CardTitle>
119	      </CardHeader>
120	      <AlertsDrawer sortedAlerts={alerts} />
121	    </Card>
122	  );
123	};
124	
125	export default AlertsCard;

